// Calculate last month's date range
const now = new Date();
const firstThisMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const firstLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);

const pad = (n) => String(n).padStart(2, '0');
const fmt = (d) => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;

return [{
  json: {
    startDate: fmt(firstLastMonth),
    endDate: fmt(firstThisMonth),
    monthLabel: firstLastMonth.toLocaleString('en-CA', { month: 'long', year: 'numeric' }),
  }
}];

const data = $input.item.json;
const monthLabel = $('Date Range').item.json.monthLabel;

const receipts = data?.QueryResponse?.SalesReceipt ?? [];
const count = receipts.length;

let totalRevenue = 0;
const productCounts = {};

for (const receipt of receipts) {
  totalRevenue += receipt.TotalAmt || 0;
  for (const line of (receipt.Line || [])) {
    if (line.DetailType === 'SalesItemLineDetail') {
      const name = line.Description || line.SalesItemLineDetail?.ItemRef?.name || 'Unknown';
      const qty = line.SalesItemLineDetail?.Qty || 1;
      productCounts[name] = (productCounts[name] || 0) + qty;
    }
  }
}

const topProducts = Object.entries(productCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => `  • ${name}: ${qty} unit${qty > 1 ? 's' : ''}`)
  .join('\n');

const fmt = (n) => new Intl.NumberFormat('en-CA', { style: 'currency', currency: 'CAD', maximumFractionDigits: 0 }).format(n);

const message = [
  `📊 *BIH Monthly Report — ${monthLabel}*`,
  ``,
  `💰 Revenue: *${fmt(totalRevenue)}*`,
  `📦 Orders: *${count}*`,
  count > 0 ? `📈 Avg order: *${fmt(totalRevenue / count)}*` : null,
  ``,
  topProducts ? `*Top Products:*\n${topProducts}` : '*No sales recorded*',
  ``,
  `_Generated by n8n · BIH automation_`,
].filter(Boolean).join('\n');

return [{ json: { message, count, totalRevenue, monthLabel } }];
